
const TEAM_COLORS = [
  { main:'#FF0000', light:'#ffe5e5', tag:'tag-t0' },
  { main:'#00235a', light:'#e6edf7', tag:'tag-t1' },
  { main:'#5b6f99', light:'#edf2fb', tag:'tag-t2' },
  { main:'#9b111e', light:'#ffe5e5', tag:'tag-t3' },
];
const PAL = ['#FF0000','#00235a','#5b6f99','#9b111e','#ff6666','#30476f','#cc0000','#00183d'];
const COLS = ['Sr.','Date','Contact No','Name','Requirement','Location','Company','Mail',
  'Status','Not Interested Reason','Interested','Next Follow-up Date',
  'Quotation Sent?','PI Sent?','Advance Received','Production Given',
  'Dispatch Date','Payment Status','Discussion / Remarks'];
const PAGE = 25;
const CHARTS = {};
const LOGIN_PASSWORD = 'ECOPEB@123';
const DEFAULT_FILE_NAMES = ['IN_Mart_Leads_Manmohan', 'IN_Mart_Leads_File_2', 'File 3', 'File 4'];
const DEFAULT_URLS = [
      'https://script.google.com/macros/s/AKfycbzfD41LD5ptpbNLLTBdy_xQ51Lk8aI-7gk56fzo03x-Cqh9jdF8eO2Zk9AUjkemRjzAow/exec',
  '',
  ''
];
let ALL = [], DASH_DATA = [], FILT = [], pg = 1, sortKey = 'Date', sortDir = 1;
let teamNames = [...DEFAULT_FILE_NAMES];
let teamURLs   = [...DEFAULT_URLS];
let refreshTimer = null;
window.onload = () => {
  buildInputRows();
  loadSaved();
  tick(); setInterval(tick, 1000);
  const logged = sessionStorage.getItem('eco_dash_login') === 'yes';
  if (logged) openAfterLogin(true);
  else document.getElementById('login-pass')?.focus();
};
function doLogin(ev) {
  if (ev) ev.preventDefault();
  const pass = document.getElementById('login-pass').value.trim();
  if (pass === LOGIN_PASSWORD) {
    sessionStorage.setItem('eco_dash_login', 'yes');
    openAfterLogin(false);
  } else {
    const er = document.getElementById('login-error');
    er.style.display = 'block';
    document.getElementById('login-pass').select();
  }
  return false;
}
function openAfterLogin(autoLoad) {
  document.getElementById('login').style.display = 'none';
  document.getElementById('config').style.display = 'none';
  document.getElementById('dash').style.display = 'none';
  if (teamURLs.some(u=>u.trim())) goDash();
  else document.getElementById('config').style.display = 'flex';
}
function logoutDash() {
  sessionStorage.removeItem('eco_dash_login');
  document.getElementById('dash').style.display = 'none';
  document.getElementById('config').style.display = 'none';
  document.getElementById('login').style.display = 'flex';
  document.getElementById('login-pass').value = '';
  document.getElementById('login-pass').focus();
}
function tick() {
  const el = document.getElementById('tb-time');
  if (el) el.textContent = new Date().toLocaleString('en-IN', {
    day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit', hour12:false
  });
}
function toggleHowTo() {
  const body = document.getElementById('howto-body');
  const arrow = document.getElementById('ht-arrow');
  body.classList.toggle('open');
  arrow.classList.toggle('open');
}
function buildInputRows() {
  const c = document.getElementById('team-rows');
  c.innerHTML = '';
  for (let i = 0; i < 4; i++) {
    const tc = TEAM_COLORS[i];
    c.innerHTML += `
    <div class="team-row">
      <div class="team-label">
        <div class="dot" style="background:${tc.main}"></div>
        <input class="label-text" id="tn${i}" placeholder="File ${i+1} name"
          style="background:none;border:none;outline:none;font-family:'JetBrains Mono',monospace;font-size:.8rem;color:var(--ink2);cursor:text;width:110px;"
          value="File ${i+1}">
      </div>
      <div class="field-wrap">
        <input id="url${i}" placeholder="Paste CSV URL for File ${i+1}…"
          oninput="validateURL(${i})" autocomplete="off" spellcheck="false">
        <span class="field-status" id="fs${i}"></span>
      </div>
    </div>`;
  }
}
function validateURL(i) {
  const val = document.getElementById('url'+i).value.trim();
  const inp = document.getElementById('url'+i);
  const sta = document.getElementById('fs'+i);
  if (!val) { inp.classList.remove('ok'); sta.textContent=''; sta.classList.remove('show'); return; }
  try { new URL(val); inp.classList.add('ok'); sta.textContent='✓'; sta.classList.add('show'); }
  catch { inp.classList.remove('ok'); sta.textContent='✗'; sta.classList.add('show'); }
}
function fileNameFromDefaultURL(url, fallback) {
  const clean = String(url || '').trim();
  const map = {
    'https://script.google.com/macros/s/AKfycbxeN3s8AdpuqSSkgIKOBZebmPSfVApW_bt5HeO9RtgKAQf9W4DAfT6Rle9N2LDPXOfxrg/exec': 'IN_Mart_Leads_Manmohan',
    'https://script.google.com/macros/s/AKfycbzfD41LD5ptpbNLLTBdy_xQ51Lk8aI-7gk56fzo03x-Cqh9jdF8eO2Zk9AUjkemRjzAow/exec': 'IN_Mart_Leads_File_2'
  };
  return map[clean] || fallback;
}
function loadSaved() {
  try {
    const s = JSON.parse(localStorage.getItem('inmart_v4') || '{}');
    teamNames = [...DEFAULT_FILE_NAMES];
    if (s.names) s.names.forEach((v,i) => { if (i > 1 && v && String(v).trim()) teamNames[i] = v; });
    [0,1,2,3].forEach(i => { document.getElementById('tn'+i).value = teamNames[i] || ('File ' + (i+1)); });
    teamURLs = [...DEFAULT_URLS];
    if (s.urls) {
      [2,3].forEach(i => { if (s.urls[i] && String(s.urls[i]).trim()) teamURLs[i] = s.urls[i]; });
    }
    teamURLs.forEach((v,i) => {
      teamNames[i] = fileNameFromDefaultURL(v, teamNames[i] || ('File ' + (i+1)));
      document.getElementById('tn'+i).value = teamNames[i];
      document.getElementById('url'+i).value=v||'';
      if(v) validateURL(i);
    });
  } catch(e) {}
}
function saveCfg() {
  teamNames = [0,1,2,3].map(i => document.getElementById('tn'+i).value.trim() || 'File '+(i+1));
  teamURLs  = [0,1,2,3].map(i => document.getElementById('url'+i).value.trim());
  localStorage.setItem('inmart_v4', JSON.stringify({ names: teamNames, urls: teamURLs }));
}
function showConfig() {
  document.getElementById('config').style.display = 'flex';
  document.getElementById('dash').style.display = 'none';
}
async function goDash() {
  saveCfg();
  if (!teamURLs.some(u => u.trim())) { showErr('Please paste at least one CSV URL.'); return; }
  const btn = document.getElementById('go-btn');
  btn.disabled = true;
  btn.innerHTML = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="animation:spin .8s linear infinite"><path d="M3 12a9 9 0 0 1 9-9 9.75 9.75 0 0 1 6.74 2.74L21 8"/><path d="M21 3v5h-5"/></svg> Fetching data…`;
  hideErr();
  try {
    await loadAll();
    document.getElementById('config').style.display = 'none';
    document.getElementById('dash').style.display = 'block';
    renderDash();
    if (refreshTimer) clearInterval(refreshTimer);
    refreshTimer = setInterval(doRefresh, 5 * 60 * 1000);
  } catch(e) {
    showErr(e.message);
  } finally {
    btn.disabled = false;
    btn.innerHTML = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg> Load Dashboard`;
  }
}
async function loadAll() {
  ALL = [];
  const jobs = teamURLs.map((url, i) => url.trim() ? fetchCSV(url.trim(), i) : Promise.resolve([]));
  const results = await Promise.allSettled(jobs);
  const errors = [];
  results.forEach((r, i) => {
    if (r.status === 'fulfilled') ALL.push(...r.value);
    else if (teamURLs[i].trim()) errors.push(`File ${i+1} (${teamNames[i]}): ${r.reason.message}`);
  });
  if (!ALL.length && errors.length) throw new Error(errors.join('\n'));
  if (errors.length) console.warn('Some teams failed:', errors);
}
function resolveURL(url) {
  if (url.includes('docs.google.com/spreadsheets')) {
    const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
    const gid = url.match(/gid=([0-9]+)/);
    if (m) return `https://docs.google.com/spreadsheets/d/${m[1]}/export?format=csv&gid=${gid ? gid[1] : '0'}`;
  }
  if (url.includes('1drv.ms') || url.includes('onedrive.live.com')) {
    const b64 = btoa(url).replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');
    return `https://api.onedrive.com/v1.0/shares/u!${b64}/root/content`;
  }
  if (url.includes('sharepoint.com') && !url.includes('download=1')) {
    return url.includes('?') ? url + '&download=1' : url + '?download=1';
  }
  return url;
}
async function fetchCSV(rawURL, teamIdx) {
  const url = resolveURL(rawURL);
  let res, text = '';
  try {
    const sep = url.includes('?') ? '&' : '?';
    res = await fetch(url + sep + 't=' + Date.now(), {
      method: 'GET',
      headers: { 'Accept': 'text/csv,text/plain,application/json,*/*' },
      cache: 'no-store'
    });
  } catch (err) {
    throw new Error('Failed to fetch. Check Apps Script deployment: Execute as Me, access Anyone, and use the /exec URL.');
  }
  if (!res.ok) throw new Error(`HTTP ${res.status} — Check that the Apps Script URL is public and ends with /exec.`);
  text = await res.text();
  if (text.includes('<!DOCTYPE') || text.includes('<html') || text.includes('Sign in')) {
    throw new Error('The URL returned HTML/login page instead of CSV. Use the Apps Script /exec URL.');
  }
  const trimmed = text.trim();
  if (trimmed.startsWith('{')) {
    try {
      const payload = JSON.parse(trimmed);
      if (payload.fileName) {
        teamNames[teamIdx] = String(payload.fileName).trim();
        const nameInp = document.getElementById('tn' + teamIdx);
        if (nameInp) nameInp.value = teamNames[teamIdx];
      }
      if (payload.csv) text = String(payload.csv);
    } catch(e) {}
  }
  const firstLine = text.split(/\r?\n/, 1)[0] || '';
  const meta = firstLine.match(/^#FILE_NAME=(.+)$/i);
  if (meta) {
    teamNames[teamIdx] = meta[1].trim();
    const nameInp = document.getElementById('tn' + teamIdx);
    if (nameInp) nameInp.value = teamNames[teamIdx];
  }
  return parseCSV(text, teamIdx);
}
function parseCSV(text, teamIdx) {
  const lines = text.replace(/\r\n/g,'\n').replace(/\r/g,'\n').trim().split('\n').filter(line => !/^#FILE_NAME=/i.test(line.trim()));
  if (lines.length < 2) return [];
  const headers = splitLine(lines[0]);
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const vals = splitLine(lines[i]);
    if (vals.every(v => !v.trim())) continue;
    const rec = { _team: teamNames[teamIdx], _teamIdx: teamIdx };
    headers.forEach((h, j) => {
      const canon = COLS.find(c => c.trim().toLowerCase() === h.trim().toLowerCase()) || h.trim();
      rec[canon] = vals[j] != null ? vals[j].trim() : '';
    });
    if (!rec['Name'] && !rec['Contact No'] && !rec['Requirement']) continue;
    rows.push(rec);
  }
  return rows;
}
function splitLine(line) {
  const result = [];
  let cur = '', inQ = false;
  for (let i = 0; i <= line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQ && line[i+1] === '"') { cur += '"'; i++; }
      else inQ = !inQ;
    } else if ((ch === ',' || ch === undefined) && !inQ) {
      result.push(cur); cur = '';
    } else cur += (ch || '');
  }
  return result;
}
async function doRefresh() {
  const btn = document.getElementById('ref-btn');
  btn.classList.add('spin');
  const pb = document.getElementById('prog-bar');
  pb.style.display = 'block';
  try { await loadAll(); renderDash(); }
  catch(e) { console.error('Refresh error:', e); }
  finally { btn.classList.remove('spin'); pb.style.display = 'none'; }
}
function escapeHtml(v) {
  return String(v ?? '').replace(/[&<>"']/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]));
}
function viewRows() {
  const sel = document.getElementById('analysis-file')?.value || '';
  return sel === '' ? ALL : ALL.filter(r => String(r._teamIdx) === sel);
}
function populateAnalysisFiles() {
  const el = document.getElementById('analysis-file');
  if (!el) return;
  const old = el.value;
  const active = [...new Set(ALL.map(r => r._teamIdx))].sort();
  el.innerHTML = '<option value="">All Files Analysis</option>' + active.map(i => `<option value="${i}">${escapeHtml(teamNames[i] || ('File ' + (Number(i)+1)))} Analysis</option>`).join('');
  if ([...el.options].some(o => o.value === old)) el.value = old;
}
function updateAnalysisHeader() {
  const sel = document.getElementById('analysis-file')?.value || '';
  const title = document.getElementById('analysis-title');
  const sub = document.getElementById('analysis-sub');
  if (!title || !sub) return;
  if (sel === '') {
    title.textContent = 'All Files Analysis';
    sub.textContent = `${ALL.length.toLocaleString('en-IN')} total records merged from all loaded files`;
  } else {
    const rows = viewRows();
    title.textContent = `${teamNames[Number(sel)]} Analysis`;
    sub.textContent = `${rows.length.toLocaleString('en-IN')} records from selected file`;
  }
}
function renderDash() {
  populateAnalysisFiles();
  DASH_DATA = viewRows();
  updateAnalysisHeader();
  buildKPIs();
  buildTeamStrip();
  buildCharts();
  populateFilters();
  FILT = [...DASH_DATA];
  pg = 1;
  renderTable();
}
function counter(arr, key) {
  const m = {};
  arr.forEach(r => { const v = (r[key]||'').trim() || 'Unknown'; m[v] = (m[v]||0) + 1; });
  return m;
}
function topN(obj, n = 10) {
  return Object.entries(obj).sort((a,b) => b[1]-a[1]).slice(0, n);
}
function trunc(v, n) {
  if (!v) return '—';
  const s = String(v).trim();
  return s ? (s.length > n ? s.slice(0, n) + '…' : s) : '—';
}
function pct(n, t) { return t ? ((n/t)*100).toFixed(1)+'%' : '—'; }
function buildKPIs() {
  const t = DASH_DATA.length;
  const interested = DASH_DATA.filter(r => /yes/i.test(r['Interested']||'')).length;
  const quot = DASH_DATA.filter(r => /yes/i.test(r['Quotation Sent?']||'')).length;
  const pi   = DASH_DATA.filter(r => /yes/i.test(r['PI Sent?']||'')).length;
  const pay  = DASH_DATA.filter(r => (r['Payment Status']||'').trim()).length;
  const cards = [
    { icon:'📊', label:'Total Leads',  val:t.toLocaleString('en-IN'), sub:`${[...new Set(DASH_DATA.map(r=>r._teamIdx))].length} teams`, c:'var(--amber)' },
    { icon:'✅', label:'Interested',   val:interested.toLocaleString('en-IN'), sub:pct(interested,t)+' rate', c:'var(--teal)' },
    { icon:'📄', label:'Quotations',   val:quot.toLocaleString('en-IN'), sub:pct(quot,t)+' of total', c:'var(--indigo)' },
    { icon:'📑', label:'PI Sent',      val:pi.toLocaleString('en-IN'), sub:pct(pi,t)+' of total', c:'var(--sky)' },
    { icon:'💰', label:'Payments',     val:pay.toLocaleString('en-IN'), sub:'have payment data', c:'var(--rose)' },
  ];
  document.getElementById('kgrid').innerHTML = cards.map(c => `
    <div class="kcard" style="--kc:${c.c}">
      <div class="kcard-icon">${c.icon}</div>
      <div class="kcard-val">${c.val}</div>
      <div class="kcard-label">${c.label}</div>
      <div class="kcard-sub">${c.sub}</div>
      <div class="kcard-accent"></div>
    </div>`).join('');
}
function buildTeamStrip() {
  const active = [...new Set(DASH_DATA.map(r => r._teamIdx))].sort();
  document.getElementById('team-strip').innerHTML = active.map(i => {
    const d = DASH_DATA.filter(r => r._teamIdx === i);
    const int = d.filter(r => /yes/i.test(r['Interested']||'')).length;
    const q   = d.filter(r => /yes/i.test(r['Quotation Sent?']||'')).length;
    const tc  = TEAM_COLORS[i];
    return `
    <div class="tc">
      <div class="tc-bar" style="background:${tc.main}"></div>
      <div class="tc-header">
        <div class="tc-avatar" style="background:${tc.light};color:${tc.main}">
          ${teamNames[i].slice(0,2).toUpperCase()}
        </div>
        <div>
          <div class="tc-name">${teamNames[i]}</div>
          <div class="tc-sub">${d.length} leads</div>
        </div>
      </div>
      <div class="tc-nums">
        <div class="tc-num">
          <div class="tc-num-val" style="color:${tc.main}">${d.length}</div>
          <div class="tc-num-lbl">Leads</div>
        </div>
        <div class="tc-num">
          <div class="tc-num-val" style="color:${tc.main}">${int}</div>
          <div class="tc-num-lbl">Interested</div>
        </div>
        <div class="tc-num">
          <div class="tc-num-val" style="color:${tc.main}">${q}</div>
          <div class="tc-num-lbl">Quotations</div>
        </div>
        <div class="tc-num">
          <div class="tc-num-val" style="color:${tc.main}">${d.length ? ((int/d.length)*100).toFixed(0) : 0}%</div>
          <div class="tc-num-lbl">Conv.</div>
        </div>
      </div>
    </div>`;
  }).join('') || '<div class="empty-state">No team data</div>';
}
const chartDefaults = {
  responsive: true,
  maintainAspectRatio: true,
  animation: { duration: 500, easing: 'easeOutQuart' },
  plugins: {
    legend: {
      labels: { color: '#9e9791', font: { family: "'JetBrains Mono'", size: 11 }, padding: 12, boxWidth: 10, boxHeight: 10 }
    },
    tooltip: {
      backgroundColor: '#1a1714',
      titleColor: '#f0ede8',
      bodyColor: '#9e9791',
      borderColor: '#2d2a27',
      borderWidth: 1,
      padding: 10,
      cornerRadius: 8,
    }
  }
};
const axisDefaults = {
  x: { ticks: { color: '#9e9791', font: { family: "'JetBrains Mono'", size: 10 } }, grid: { color: '#e2ddd8' } },
  y: { ticks: { color: '#9e9791', font: { family: "'JetBrains Mono'", size: 10 } }, grid: { color: '#e2ddd8' } }
};
function mkChart(id, type, labels, datasets, extra = {}) {
  if (CHARTS[id]) CHARTS[id].destroy();
  const el = document.getElementById(id); if (!el) return;
  CHARTS[id] = new Chart(el.getContext('2d'), {
    type,
    data: { labels, datasets },
    options: {
      ...chartDefaults,
      scales: (type === 'bar' || type === 'line') ? axisDefaults : undefined,
      ...extra
    }
  });
}
function buildCharts() {
  const active = [...new Set(DASH_DATA.map(r => r._teamIdx))].sort();
  const dm = {};
  DASH_DATA.forEach(r => {
    let d = (r['Date']||'').trim();
    if (!d) return;
    if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(d)) {
      const p = d.split('/');
      d = `${p[2]}-${p[0].padStart(2,'0')}-${p[1].padStart(2,'0')}`;
    }
    if (!dm[d]) dm[d] = {};
    dm[d][r._teamIdx] = (dm[d][r._teamIdx]||0) + 1;
  });
  const dates = Object.keys(dm).sort();
  document.getElementById('tl-badge').textContent = dates.length
    ? `${dates[0]} → ${dates[dates.length-1]}` : '';
  mkChart('ch-tl', 'line', dates,
    active.map(i => ({
      label: teamNames[i],
      data: dates.map(d => dm[d]?.[i]||0),
      borderColor: TEAM_COLORS[i].main,
      backgroundColor: TEAM_COLORS[i].main + '20',
      tension: 0.4, fill: true, pointRadius: 4, pointHoverRadius: 6,
      borderWidth: 2,
    }))
  );
  const tCounts = active.map(i => DASH_DATA.filter(r => r._teamIdx === i).length);
  document.getElementById('b-teams').textContent = DASH_DATA.length + ' total';
  mkChart('ch-teams', 'doughnut',
    active.map(i => teamNames[i]),
    [{ data: tCounts, backgroundColor: active.map(i => TEAM_COLORS[i].main), borderColor: '#fff', borderWidth: 3, hoverOffset: 6 }]
  );
  const sc = counter(DASH_DATA, 'Status'); delete sc['Unknown'];
  const se = topN(sc, 8);
  if (se.length) mkChart('ch-status', 'bar',
    se.map(e => trunc(e[0], 20)),
    [{ data: se.map(e=>e[1]), backgroundColor: PAL.map(c=>c+'bb'), borderColor: PAL, borderWidth: 1, borderRadius: 4 }],
    { plugins: { ...chartDefaults.plugins, legend: { display: false } } }
  );
  const ic = counter(DASH_DATA, 'Interested'); delete ic['Unknown'];
  const ie = topN(ic, 5);
  if (ie.length) mkChart('ch-int', 'pie',
    ie.map(e => e[0]),
    [{ data: ie.map(e=>e[1]), backgroundColor: ['#00235a','#FF0000','#FF0000','#00235a','#6b7280'], borderColor: '#fff', borderWidth: 2 }]
  );
  const lc = {};
  DASH_DATA.forEach(r => {
    const loc = r['Location']||'';
    const parts = loc.split(',').map(s=>s.trim());
    const state = parts.length >= 3 ? parts[parts.length-2] : (parts[0]||'');
    if (state && state !== 'India' && state.length > 1) lc[state] = (lc[state]||0)+1;
  });
  const le = topN(lc, 12);
  if (le.length) mkChart('ch-loc', 'bar',
    le.map(e => e[0]),
    [{ data: le.map(e=>e[1]), backgroundColor: '#00235abb', borderColor: '#00235a', borderWidth: 1, borderRadius: 4 }],
    { indexAxis: 'y', plugins: { ...chartDefaults.plugins, legend: { display: false } } }
  );
  const fd = [
    { l: 'Total Leads',      v: DASH_DATA.length },
    { l: 'Interested',       v: DASH_DATA.filter(r=>/yes/i.test(r['Interested']||'')).length },
    { l: 'Quotation Sent',   v: DASH_DATA.filter(r=>/yes/i.test(r['Quotation Sent?']||'')).length },
    { l: 'PI Sent',          v: DASH_DATA.filter(r=>/yes/i.test(r['PI Sent?']||'')).length },
    { l: 'Advance Received', v: DASH_DATA.filter(r=>(r['Advance Received']||'').trim()).length },
    { l: 'Dispatched',       v: DASH_DATA.filter(r=>(r['Dispatch Date']||'').trim()).length },
  ].filter(d => d.v > 0);
  mkChart('ch-funnel', 'bar',
    fd.map(d => d.l),
    [{ data: fd.map(d=>d.v), backgroundColor: PAL.map(c=>c+'88'), borderColor: PAL, borderWidth: 1, borderRadius: 4 }],
    { indexAxis: 'y', plugins: { ...chartDefaults.plugins, legend: { display: false } } }
  );
  const rc = counter(DASH_DATA, 'Requirement'); delete rc['Unknown'];
  const re = topN(rc, 10);
  if (re.length) mkChart('ch-req', 'bar',
    re.map(e => trunc(e[0], 40)),
    [{ data: re.map(e=>e[1]), backgroundColor: '#FF000088', borderColor: '#FF0000', borderWidth: 1, borderRadius: 4 }],
    { indexAxis: 'y', plugins: { ...chartDefaults.plugins, legend: { display: false } } }
  );
  const pc = counter(DASH_DATA, 'Payment Status'); delete pc['Unknown'];
  const pe = topN(pc, 6);
  if (pe.length) mkChart('ch-pay', 'doughnut',
    pe.map(e => e[0]),
    [{ data: pe.map(e=>e[1]), backgroundColor: PAL.map(c=>c+'cc'), borderColor: '#fff', borderWidth: 3 }]
  );
}
function parseAnyDate(v) {
  if (!v) return null;
  const s = String(v).trim();
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return new Date(s + 'T00:00:00');
  let m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) {
    const a = +m[1], b = +m[2], y = +m[3];
    const d = a > 12 ? a : b;
    const mo = a > 12 ? b : a;
    return new Date(y, mo - 1, d);
  }
  const d = new Date(s);
  return isNaN(d) ? null : d;
}
function locationBucket(loc) {
  const parts = String(loc || '').split(',').map(s => s.trim()).filter(Boolean);
  if (!parts.length) return '';
  if (parts.length >= 3) return parts[parts.length - 2];
  return parts[0];
}
function ynValue(v) {
  return /yes/i.test(String(v || '').trim()) ? 'yes' : 'no';
}
function populateSelect(id, label, values) {
  const el = document.getElementById(id);
  if (!el) return;
  el.innerHTML = `<option value="">${label}</option>`;
  values.filter(Boolean).filter(v => String(v).trim()).sort((a,b)=>String(a).localeCompare(String(b)))
    .forEach(v => el.innerHTML += `<option>${String(v)}</option>`);
}
function populateFilters() {
  populateSelect('f-team', 'All Files', [...new Set(DASH_DATA.map(r=>r._team))]);
  populateSelect('f-status', 'All Status', [...new Set(DASH_DATA.map(r=>r['Status']))]);
  populateSelect('f-int', 'All Interested', [...new Set(DASH_DATA.map(r=>r['Interested']))]);
  populateSelect('f-req', 'All Requirements', [...new Set(DASH_DATA.map(r=>r['Requirement']))]);
  populateSelect('f-state', 'All States/Locations', [...new Set(DASH_DATA.map(r=>locationBucket(r['Location'])))]) ;
  populateSelect('f-pay', 'Payment: All', [...new Set(DASH_DATA.map(r=>r['Payment Status']))]);
}
function filterTable() {
  const team   = document.getElementById('f-team')?.value || '';
  const status = document.getElementById('f-status')?.value || '';
  const int    = document.getElementById('f-int')?.value || '';
  const req    = document.getElementById('f-req')?.value || '';
  const state  = document.getElementById('f-state')?.value || '';
  const quot   = document.getElementById('f-quot')?.value || '';
  const pi     = document.getElementById('f-pi')?.value || '';
  const pay    = document.getElementById('f-pay')?.value || '';
  const follow = document.getElementById('f-follow')?.value || '';
  const fromD  = parseAnyDate(document.getElementById('f-from')?.value || '');
  const toD    = parseAnyDate(document.getElementById('f-to')?.value || '');
  const q      = (document.getElementById('f-search')?.value || '').toLowerCase().trim();
  const today  = new Date(); today.setHours(0,0,0,0);
  FILT = DASH_DATA.filter(r => {
    if (team   && r._team !== team) return false;
    if (status && (r['Status']||'') !== status) return false;
    if (int    && (r['Interested']||'') !== int) return false;
    if (req    && (r['Requirement']||'') !== req) return false;
    if (state  && locationBucket(r['Location']) !== state) return false;
    if (quot   && ynValue(r['Quotation Sent?']) !== quot) return false;
    if (pi     && ynValue(r['PI Sent?']) !== pi) return false;
    if (pay    && (r['Payment Status']||'') !== pay) return false;
    const rowDate = parseAnyDate(r['Date']);
    if (fromD && rowDate && rowDate < fromD) return false;
    if (toD && rowDate && rowDate > toD) return false;
    if ((fromD || toD) && !rowDate) return false;
    if (follow) {
      const fd = parseAnyDate(r['Next Follow-up Date']);
      if (follow === 'blank' && fd) return false;
      if (follow !== 'blank' && !fd) return false;
      if (follow === 'today' && fd.getTime() !== today.getTime()) return false;
      if (follow === 'overdue' && fd >= today) return false;
      if (follow === 'upcoming' && fd < today) return false;
    }
    if (q) {
      const hay = [r['Name'],r['Location'],r['Requirement'],r['Company'],r['Contact No'],r['Mail'],r['Status'],r['Payment Status'],r['Discussion / Remarks']].join(' ').toLowerCase();
      if (!hay.includes(q)) return false;
    }
    return true;
  });
  pg = 1;
  renderTable();
}
function clearCrmFilters() {
  ['f-team','f-status','f-int','f-req','f-state','f-quot','f-pi','f-pay','f-follow','f-from','f-to','f-search'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = '';
  });
  filterTable();
}
let _sortKey = 'Date', _sortDir = 1;
function sortBy(k) {
  document.querySelectorAll('thead th').forEach(th => { th.classList.remove('sort-asc','sort-desc'); });
  if (_sortKey === k) _sortDir *= -1; else { _sortKey = k; _sortDir = 1; }
  event.target.classList.add(_sortDir === 1 ? 'sort-asc' : 'sort-desc');
  filterTable();
}
function renderTable() {
  const sorted = [...FILT].sort((a,b) => {
    const av = (a[_sortKey]||''), bv = (b[_sortKey]||'');
    return av < bv ? -_sortDir : av > bv ? _sortDir : 0;
  });
  const total = sorted.length;
  const start = (pg - 1) * PAGE;
  const rows  = sorted.slice(start, start + PAGE);
  document.getElementById('tbl-title').innerHTML =
    `All Leads <span>${total.toLocaleString('en-IN')} results</span>`;
  const statusTag = s => {
    if (!s || !s.trim()) return '—';
    if (/interested|yes/i.test(s)) return `<span class="tag tag-green">${trunc(s,18)}</span>`;
    if (/quotation|pi sent/i.test(s)) return `<span class="tag tag-blue">${trunc(s,18)}</span>`;
    if (/not|reject|cancel/i.test(s)) return `<span class="tag tag-orange">${trunc(s,18)}</span>`;
    return `<span class="tag tag-gray">${trunc(s,18)}</span>`;
  };
  const tbody = document.getElementById('tbody');
  if (!rows.length) {
    tbody.innerHTML = `<tr><td colspan="13" class="empty-state">No leads match your filters</td></tr>`;
  } else {
    tbody.innerHTML = rows.map(r => {
      const tc = TEAM_COLORS[r._teamIdx] || TEAM_COLORS[0];
      return `<tr>
        <td><span class="tag ${tc.tag || 'tag-t0'}">${r._team}</span></td>
        <td style="font-family:'JetBrains Mono',monospace;font-size:.7rem;color:var(--ink2)">${r['Date']||'—'}</td>
        <td><strong>${trunc(r['Name'],22)}</strong></td>
        <td style="font-family:'JetBrains Mono',monospace;font-size:.7rem;color:var(--ink3)">${(r['Contact No']||'—').replace(/^\?/,'').replace(/^\u200b/,'')}</td>
        <td title="${r['Requirement']||''}">${trunc(r['Requirement'],38)}</td>
        <td title="${r['Location']||''}">${trunc(r['Location'],30)}</td>
        <td>${trunc(r['Company'],20)}</td>
        <td>${statusTag(r['Status'])}</td>
        <td>${r['Interested'] ? `<span class="tag ${/yes/i.test(r['Interested'])?'tag-green':'tag-orange'}">${r['Interested']}</span>` : '—'}</td>
        <td style="text-align:center">${r['Quotation Sent?'] || '—'}</td>
        <td style="text-align:center">${r['PI Sent?'] || '—'}</td>
        <td style="font-size:.72rem">${r['Payment Status'] || '—'}</td>
        <td style="font-family:'JetBrains Mono',monospace;font-size:.7rem;color:var(--ink3)">${r['Next Follow-up Date']||'—'}</td>
      </tr>`;
    }).join('');
  }
  const totalPages = Math.ceil(total / PAGE);
  document.getElementById('pag-info').textContent = `${start+1}–${Math.min(start+PAGE,total)} of ${total}`;
  const pb = document.getElementById('pag-btns');
  pb.innerHTML = '';
  const mkBtn = (label, p, active=false) => {
    const b = document.createElement('button');
    b.className = 'pag-btn' + (active ? ' on' : '');
    b.textContent = label;
    b.onclick = () => { pg = p; renderTable(); };
    pb.appendChild(b);
  };
  if (pg > 1) mkBtn('←', pg - 1);
  const s2 = Math.max(1, pg - 2), e2 = Math.min(totalPages, s2 + 4);
  for (let p = s2; p <= e2; p++) mkBtn(p, p, p === pg);
  if (pg < totalPages) mkBtn('→', pg + 1);
}
function showErr(m) {
  const e = document.getElementById('err-box');
  e.textContent = m; e.style.display = 'block'; e.style.whiteSpace = 'pre-line';
}
function hideErr() { document.getElementById('err-box').style.display = 'none'; }
